import{_ as e,o as t,c as a,a2 as i}from"./chunks/framework.BflysNKA.js";const y=JSON.parse('{"title":"修改令牌设置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/modify-token.md","filePath":"guide/modify-token.md","lastUpdated":1778577020000}'),r={name:"guide/modify-token.md"};function o(d,l,n,h,s,p){return t(),a("div",null,[...l[0]||(l[0]=[i('<h1 id="修改令牌设置" tabindex="-1">修改令牌设置 <a class="header-anchor" href="#修改令牌设置" aria-label="Permalink to &quot;修改令牌设置&quot;">​</a></h1><p>令牌创建后仍可在控制台调整启用状态、额度、模型权限和有效期。</p><p>修改后会影响后续请求。已经发出的请求可能不会立即停止。</p><p>修改令牌的意义，不只是“把某个字段改一下”，而是让同一把 Key 的可用范围更贴近当前场景。比如：临时测试结束后收紧额度、给脚本单独限制模型、怀疑泄露时先禁用。</p><h2 id="可调整内容" tabindex="-1">可调整内容 <a class="header-anchor" href="#可调整内容" aria-label="Permalink to &quot;可调整内容&quot;">​</a></h2><p>登录控制台，进入 <strong>令牌管理</strong>，点击令牌右侧的编辑按钮。</p><p>修改前先想清楚你现在要解决的是哪一类问题：</p><ul><li>只是想限制预算</li><li>只是想限制模型范围</li><li>只是想临时停用</li><li>还是这把 Key 的使用对象已经变了</li></ul><p>把问题先分清楚，才容易判断应该“编辑原 Key”还是“直接新建一把”。</p><h3 id="_1-额度控制" tabindex="-1">1. 额度控制 <a class="header-anchor" href="#_1-额度控制" aria-label="Permalink to &quot;1. 额度控制&quot;">​</a></h3><ul><li>批量脚本、自动化任务和共享测试 Key 建议设置总配额。</li><li>团队测试 Key 可设置周期额度。</li><li>达到额度后，网关会拒绝该 Key 的后续请求。</li></ul><p>额度更适合解决这类问题：</p><ul><li>担心脚本误循环把余额快速打空</li><li>想给测试同学或外包同事一个可控上限</li><li>想把桌面聊天和 CLI 编程的预算分开</li></ul><h3 id="_2-启用或禁用" tabindex="-1">2. 启用或禁用 <a class="header-anchor" href="#_2-启用或禁用" aria-label="Permalink to &quot;2. 启用或禁用&quot;">​</a></h3><p>遇到以下情况，先禁用对应 Key：</p><ul><li>怀疑项目的 <code>.env</code> 文件被意外 Push 到了公共仓库。</li><li>离职交接或外包项目结束。</li><li>某个工具产生异常高频请求。</li></ul><p>禁用通常会很快生效。长连接或已经发出的请求可能需要等待结束。</p><p>禁用更适合“先止血，再细查”。<br> 一旦怀疑泄露或发现异常高频请求，先禁用，比一边怀疑一边继续让请求跑更稳。</p><h3 id="_3-模型权限" tabindex="-1">3. 模型权限 <a class="header-anchor" href="#_3-模型权限" aria-label="Permalink to &quot;3. 模型权限&quot;">​</a></h3><p>可以修改 Key 绑定的模型权限组。只做文本整理、翻译或轻量问答的工具，可限制为低成本模型；代码生成和长上下文任务再开放强模型。</p><p>模型权限更适合解决：</p><ul><li>某个工具不应该碰高价模型</li><li>某个共享 Key 只允许调用一小批模型</li><li>某台服务器只允许跑脚本专用模型</li></ul><h2 id="什么时候改这把-key-什么时候直接新建" tabindex="-1">什么时候改这把 Key，什么时候直接新建 <a class="header-anchor" href="#什么时候改这把-key-什么时候直接新建" aria-label="Permalink to &quot;什么时候改这把 Key，什么时候直接新建&quot;">​</a></h2><p>不是所有情况都适合继续修改原有 Key。可以按这个思路判断：</p><table tabindex="0"><thead><tr><th>场景</th><th>更适合怎么做</th><th>原因</th></tr></thead><tbody><tr><td>只是临时调小额度、调整有效期</td><td>直接编辑当前 Key</td><td>原工具配置不用重写</td></tr><tr><td>想给同一台设备补充几个可用模型</td><td>直接编辑当前 Key</td><td>对现有工作流影响最小</td></tr><tr><td>想把 Claude Code 和 Cherry Studio 的消耗分开</td><td>新建一把 Key</td><td>后续日志更清楚</td></tr><tr><td>怀疑 Key 已泄露</td><td>新建 Key，并禁用旧 Key</td><td>比继续编辑旧 Key 更稳</td></tr><tr><td>给同事、脚本或服务器单独使用</td><td>新建独立 Key</td><td>便于回收和限额</td></tr></tbody></table><p>简单说：</p><ul><li><strong>只改规则，不改身份</strong>：优先编辑</li><li><strong>换使用对象、换安全边界</strong>：优先新建</li></ul><h2 id="常见调整场景" tabindex="-1">常见调整场景 <a class="header-anchor" href="#常见调整场景" aria-label="Permalink to &quot;常见调整场景&quot;">​</a></h2><ul><li><strong>临时测试</strong>：设置较小总额度，测试完直接禁用。</li><li><strong>桌面聊天</strong>：允许常用聊天模型，额度适中。</li><li><strong>终端编程</strong>：允许代码能力强的模型，单独统计消耗。</li><li><strong>服务器脚本</strong>：必须设置额度上限，避免循环请求。</li><li><strong>共享给他人</strong>：设置过期时间和模型范围。</li></ul><p>如果你现在拿不准，先按这个最简单的判断走：</p><ul><li><strong>还想继续让原工具用同一把 Key</strong>：先编辑</li><li><strong>想把不同人、不同机器、不同工具分开</strong>：直接新建</li></ul><h2 id="修改后多久生效" tabindex="-1">修改后多久生效 <a class="header-anchor" href="#修改后多久生效" aria-label="Permalink to &quot;修改后多久生效&quot;">​</a></h2><p>禁用、额度、权限变更通常会很快影响后续请求。已经发出的请求不一定会立刻停止，所以发现泄露时建议直接禁用或删除 Key。</p><p>如果你刚修改完，最容易误判的一点是：<br> 控制台页面已经改了，不代表当前工具会话一定已经读到了新的结果。<br> 桌面客户端、长会话 CLI、后台服务，都可能还在延续旧会话或旧配置。</p><h2 id="修改后怎么确认已经生效" tabindex="-1">修改后怎么确认已经生效 <a class="header-anchor" href="#修改后怎么确认已经生效" aria-label="Permalink to &quot;修改后怎么确认已经生效&quot;">​</a></h2><p>最稳的验证方式不是只看控制台，而是做一次最小请求：</p><ol><li>修改 Key 设置</li><li>用这把 Key 再发一条最小请求</li><li>看返回是否符合预期</li><li>回控制台日志确认请求记录</li></ol><p>例如：</p><ul><li>刚禁用 Key：请求应直接失败</li><li>刚去掉某个模型权限：该模型应不再可调用</li><li>刚放宽额度：原本被限额的请求应恢复</li></ul><p>这样能把“页面上已经改了”和“客户端实际已经生效”区分开。</p><p>如果测试结果和预期不一致，再回头看三层：</p><ol><li>当前工具是不是还在用这把 Key</li><li>当前会话是不是还停留在旧模型</li><li>当前服务或终端是不是需要重新打开</li></ol><h2 id="key-泄露处理" tabindex="-1">Key 泄露处理 <a class="header-anchor" href="#key-泄露处理" aria-label="Permalink to &quot;Key 泄露处理&quot;">​</a></h2><ol><li>立即禁用或删除这把 Key。</li><li>检查日志，看最近请求是否异常。</li><li>给对应工具创建一把新 Key。</li><li>更新本地配置。</li><li>确认 Git 仓库里没有残留明文 Key。</li></ol><h2 id="备用-key" tabindex="-1">备用 Key <a class="header-anchor" href="#备用-key" aria-label="Permalink to &quot;备用 Key&quot;">​</a></h2><p>常用开发环境可以保留一把备用 Key。主力 Key 泄露、误删或触发额度后，先切换备用 Key，再处理旧配置。</p><p>备用 Key 最好也按用途区分，不要把一把“万能备用 Key”同时塞给所有工具。否则主力 Key 出问题时，备用 Key 很快又会变成新的单点。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/api/models">模型列表</a></li><li><a href="/guide/recharge">充值</a></li><li><a href="/support/troubleshooting">排障手册</a></li></ul>',49)])])}const c=e(r,[["render",o]]);export{y as __pageData,c as default};
